25: /**
26:  * The Kafka offset commit API allows users to provide additional metadata (in the form of a string)
27:  * when an offset is committed. This can be useful (for example) to store information about which
28:  * node made the commit, what time the commit was made, etc.
29:  */
30: public class OffsetAndMetadata implements Serializable {
31:     private static final long serialVersionUID = 2019555404968089681L;
32: 
33:     private final long offset;
34:     private final String metadata;
35: 
36:     // We use null to represent the absence of a leader epoch to simplify serialization.
37:     // I.e., older serializations of this class which do not have this field will automatically
38:     // initialize its value to null.
39:     private final Integer leaderEpoch;
40: 
41:     /**
42:      * Construct a new OffsetAndMetadata object for committing through {@link KafkaConsumer}.
43:      *
44:      * @param offset The offset to be committed
45:      * @param leaderEpoch Optional leader epoch of the last consumed record
46:      * @param metadata Non-null metadata
47:      */
48:     public OffsetAndMetadata(long offset, Optional<Integer> leaderEpoch, String metadata) {
49:         if (offset < 0)
50:             throw new IllegalArgumentException("Invalid negative offset");
51: 
52:         this.offset = offset;
53:         this.leaderEpoch = leaderEpoch.orElse(null);
54: 
55:         // The server converts null metadata to an empty string. So we store it as an empty string as well on the client
56:         // to be consistent.
57:         if (metadata == null)
58:             this.metadata = OffsetFetchResponse.NO_METADATA;
59:         else
60:             this.metadata = metadata;
61:     }
62: 
63:     /**
64:      * Construct a new OffsetAndMetadata object for committing through {@link KafkaConsumer}.
65:      * @param offset The offset to be committed
66:      * @param metadata Non-null metadata
67:      */
68:     public OffsetAndMetadata(long offset, String metadata) {
69:         this(offset, Optional.empty(), metadata);
70:     }
71: 
72:     /**
73:      * Construct a new OffsetAndMetadata object for committing through {@link KafkaConsumer}. The metadata
74:      * associated with the commit will be empty.
75:      * @param offset The offset to be committed
76:      */
77:     public OffsetAndMetadata(long offset) {
78:         this(offset, "");
79:     }
80: 
81:     public long offset() {
82:         return offset;
83:     }
84: 
85:     public String metadata() {
86:         return metadata;
87:     }
88: 
89:     /**
90:      * Get the leader epoch of the previously consumed record (if one is known). Log truncation is detected
91:      * if there exists a leader epoch which is larger than this epoch and begins at an offset earlier than
92:      * the committed offset.
93:      *
94:      * @return the leader epoch or empty if not known
95:      */
96:     public Optional<Integer> leaderEpoch() {
97:         if (leaderEpoch == null || leaderEpoch < 0)
98:             return Optional.empty();
99:         return Optional.of(leaderEpoch);
100:     }
101: 
102:     @Override
103:     public boolean equals(Object o) {
104:         if (this == o) return true;
105:         if (o == null || getClass() != o.getClass()) return false;
106:         OffsetAndMetadata that = (OffsetAndMetadata) o;
107:         return offset == that.offset &&
108:                 Objects.equals(metadata, that.metadata) &&
109:                 Objects.equals(leaderEpoch, that.leaderEpoch);
110:     }
111: 
112:     @Override
113:     public int hashCode() {
114:         return Objects.hash(offset, metadata, leaderEpoch);
115:     }
116: 
117:     @Override
118:     public String toString() {
119:         return "OffsetAndMetadata{" +
120:                 "offset=" + offset +
121:                 ", leaderEpoch=" + leaderEpoch +
122:                 ", metadata='" + metadata + '\'' +
123:                 '}';
124:     }
125: 
126: }
