488:     @Override
489:     public DataInputStatus emitNext(DataOutput<OUT> output) throws Exception {
490:         // guarding an assumptions we currently make due to the fact that certain classes
491:         // assume a constant output, this assumption does not need to stand if we emitted all
492:         // records. In that case the output will change to FinishedDataOutput
493:         assert lastInvokedOutput == output
494:                 || lastInvokedOutput == null
495:                 || this.operatingMode == OperatingMode.DATA_FINISHED;
496: 
497:         // short circuit the hot path. Without this short circuit (READING handled in the
498:         // switch/case) InputBenchmark.mapSink was showing a performance regression.
499:         if (operatingMode != OperatingMode.READING) {
500:             return emitNextNotReading(output);
501:         }
502: 
503:         InputStatus status;
504:         do {
505:             status = sourceReader.pollNext(currentMainOutput);
506:         } while (status == InputStatus.MORE_AVAILABLE
507:                 && canEmitBatchOfRecords.check()
508:                 && !shouldWaitForAlignment());
509:         return convertToInternalStatus(status);
510:     }
